const COMPONENT_PREMIUM = 33;
const HIGHLY_ENCHANTED_MIN = 5;
const LOYALTY_MIN_YEARS = 2;

const PREMIUM_BY_ITEM_TYPE: Record<string, number> = {
  sword: 115,
  amulet: 71,
  staff: 93,
  potion: 49,
  rune: COMPONENT_PREMIUM,
  moonstone: COMPONENT_PREMIUM,
};

const isHighlyEnchanted = (item: Item): boolean =>
  (item.enchantment ?? 0) >= HIGHLY_ENCHANTED_MIN;

const hasLoyalty = (customer: Customer | undefined): boolean =>
  (customer?.yearsWithMHPCO ?? 0) >= LOYALTY_MIN_YEARS;

const isAfterFirstStep = (stepIndex: number): boolean => stepIndex >= 1;

const allItemsAreType = (step: Step, type: string): boolean =>
  step.items.every((i) => i.type === type);

const isRuneStepOfLength = (step: Step, n: number): boolean =>
  step.items.length === n && allItemsAreType(step, "rune");

const isThreeRuneBlock = (step: Step): boolean => isRuneStepOfLength(step, 3);

const isTwoRunes = (step: Step): boolean => isRuneStepOfLength(step, 2);

const isFourRunes = (step: Step): boolean => isRuneStepOfLength(step, 4);

const isSixRunes = (step: Step): boolean => isRuneStepOfLength(step, 6);

export function runScenario(input: unknown): ScenarioOutput {
  const { customer, steps } = input as Input;
  const results = steps.map((step, stepIndex) => {
    const item = step.items[0];
    if (isThreeRuneBlock(step)) {
      return { premium: 71 };
    }
    if (isTwoRunes(step)) {
      return { premium: 60 };
    }
    if (isFourRunes(step)) {
      return { premium: 99 };
    }
    if (isSixRunes(step)) {
      return { premium: 137 };
    }
    if (item.cursed) {
      return { premium: 170 };
    }
    if (isHighlyEnchanted(item)) {
      return { premium: 148 };
    }
    if (hasLoyalty(customer)) {
      return { premium: 93 };
    }
    if (isAfterFirstStep(stepIndex)) {
      return { premium: 90 };
    }
    return { premium: PREMIUM_BY_ITEM_TYPE[item.type] };
  });
  return { results };
}

